export function getCompaniesByPriority(priority: 1 | 2 | 3): SP500Company[] {
  return SP500_COMPANIES.filter(company => company.priority === priority);
}

export function getCompaniesBySector(sector: string): SP500Company[] {
  return SP500_COMPANIES.filter(company => company.sector === sector);
}

export function getAllTickers(): string[] {
  return SP500_COMPANIES.map(company => company.ticker);
}

export function getCompanyInfo(ticker: string): SP500Company | undefined {
  return SP500_COMPANIES.find(company => company.ticker === ticker);
}

export const PROCESSING_PHASES = {
  1: getCompaniesByPriority(1),
  2: getCompaniesByPriority(2),
  3: getCompaniesByPriority(3)
};
